import React, { useState, useEffect } from 'react';
import './index.css';
import { Header } from './components/Header';
import { TaskForm } from './components/TaskForm';
import { TaskList } from './components/TaskList';
import { taskService } from './services/taskService';

function App() {
  const [tasks, setTasks] = useState([]);
  const [filter, setFilter] = useState('all');
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [showForm, setShowForm] = useState(false);

  useEffect(() => {
    loadTasks();
  }, []);

  const loadTasks = async () => {
    try {
      setLoading(true);
      setError('');
      const data = await taskService.getAllTasks();
      setTasks(data);
    } catch (err) {
      setError('Failed to load tasks. Make sure the backend is running on http://localhost:8080');
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  const handleTaskAdded = (newTask) => {
    setTasks([newTask, ...tasks]);
    setShowForm(false);
  };

  const handleTasksUpdated = (updatedTasks) => {
    setTasks(updatedTasks);
  };

  return (
    <div className="min-h-screen bg-gradient-to-br from-blue-50 to-indigo-100">
      <Header />

      <main className="max-w-6xl mx-auto px-4 pb-12">
        {error && (
          <div className="mb-6 p-4 bg-red-50 border-l-4 border-red-500 text-red-700 rounded-lg flex items-center gap-3">
            <span className="text-2xl">⚠️</span>
            <span>{error}</span>
            <button
              onClick={loadTasks}
              className="ml-auto underline hover:no-underline font-semibold"
            >
              Retry
            </button>
          </div>
        )}

        {loading && !error ? (
          <div className="text-center py-12">
            <div className="inline-block">
              <div className="animate-spin text-4xl mb-4">⏳</div>
              <p className="text-gray-600 font-medium">Loading your tasks...</p>
            </div>
          </div>
        ) : (
          <>
            {/* Add Task Button */}
            <div className="mb-6">
              <button
                onClick={() => setShowForm(!showForm)}
                className="inline-flex items-center gap-2 px-6 py-3 bg-gradient-to-r from-blue-600 to-indigo-600 text-white rounded-lg font-semibold shadow-lg hover:shadow-xl hover:scale-105 transition-all duration-200"
              >
                {showForm ? '✕ Cancel' : '➕ Add New Task'}
              </button>
            </div>

            {/* Task Form - Shown when button clicked */}
            {showForm && (
              <div className="mb-6">
                <TaskForm onTaskAdded={handleTaskAdded} />
              </div>
            )}

            {/* Filter Tabs */}
            <div className="flex gap-2 mb-6 flex-wrap">
              {[
                { value: 'all', label: '📋 All Tasks' },
                { value: 'active', label: '⚡ Active' },
                { value: 'completed', label: '✅ Completed' },
              ].map((tab) => (
                <button
                  key={tab.value}
                  onClick={() => setFilter(tab.value)}
                  className={`px-6 py-2 rounded-lg font-medium transition-all ${
                    filter === tab.value
                      ? 'bg-blue-600 text-white shadow-lg'
                      : 'bg-white text-gray-700 border-2 border-gray-200 hover:border-blue-400'
                  }`}
                >
                  {tab.label}
                </button>
              ))}
            </div>

            <TaskList
              tasks={tasks}
              filter={filter}
              onTasksUpdated={handleTasksUpdated}
            />
          </>
        )}
      </main>
    </div>
  );
}

export default App;
